var _propFiltered = [];

function initProp() {
  _propFiltered = PROP_DEALS.slice();
  _propRender();
  _propStats();
  _propPopulateFilters();
}

function _propStats() {
  var d = _propFiltered;
  var el = function(id) { return document.getElementById(id); };
  if (el('prop-stat-total')) el('prop-stat-total').textContent = d.length;
  if (el('prop-stat-hot')) el('prop-stat-hot').textContent = d.filter(function(x) { return (x.days||0)>=60; }).length;
  if (el('prop-result-count')) el('prop-result-count').textContent = d.length;
  if (el('prop-header-sub')) el('prop-header-sub').textContent = 'Gold Coast & Brisbane | $600K–$1.5M | ' + PROP_DEALS.length + ' listings';
}

function _propPopulateFilters() {
  var sel = document.getElementById('pf-suburb');
  if (!sel || sel.options.length > 1) return;
  var suburbs = [];
  PROP_DEALS.forEach(function(d) {
    var parts = (d.address||'').split(',');
    var s = parts.length > 1 ? parts[parts.length-2].trim() : '';
    if (s && suburbs.indexOf(s) === -1) suburbs.push(s);
  });
  suburbs.sort().forEach(function(s) {
    var o = document.createElement('option');
    o.value = s; o.textContent = s; sel.appendChild(o);
  });
}

function propFilter() {
  var suburb = (document.getElementById('pf-suburb')||{}).value || '';
  var beds = parseInt((document.getElementById('pf-beds')||{}).value) || 0;
  _propFiltered = PROP_DEALS.filter(function(d) {
    if (suburb && (d.address||'').indexOf(suburb) === -1) return false;
    if (beds && (d.beds||0) < beds) return false;
    return true;
  });
  _propRender();
  _propStats();
}

function propReset() { propResetFilters(); }

function propResetFilters() {
  ['pf-suburb','pf-beds','pf-days','pf-price','pf-yield','pf-rating','pf-draft'].forEach(function(id) {
    var el = document.getElementById(id);
    if (el) el.value = '';
  });
  _propFiltered = PROP_DEALS.slice();
  _propRender();
  _propStats();
}

function propSort(key, th) {
  document.querySelectorAll('.prop-table thead th').forEach(function(t) { t.classList.remove('prop-sorted'); });
  if (th) th.classList.add('prop-sorted');
  _propFiltered.sort(function(a, b) {
    var av = a[key] || 0, bv = b[key] || 0;
    if (typeof av === 'string') return av.localeCompare(bv);
    return bv - av;
  });
  _propRender();
}

function _propRender() {
  var tbody = document.getElementById('prop-tbody');
  var nr = document.getElementById('prop-no-results');
  if (!tbody) return;
  if (!_propFiltered.length) {
    tbody.innerHTML = '';
    if (nr) nr.style.display = '';
    return;
  }
  if (nr) nr.style.display = 'none';
  
  tbody.innerHTML = _propFiltered.map(function(d, i) {
    var priceNum = 0;
    var pm = (d.price||'').match(/[\d,]+/g);
    if (pm) priceNum = parseInt(pm[0].replace(/,/g,'')) || 0;
    var rent = priceNum > 0 ? Math.round(priceNum * 0.042 / 52) : 0;
    var yld = priceNum > 0 ? (rent * 52 / priceNum * 100).toFixed(1) + '%' : '—';
    var cashflow = rent > 0 ? Math.round(rent - (priceNum * 0.8 * 0.065 / 52)) : 0;
    var cfStr = cashflow > 0 ? '<span style="color:#22c55e">+$' + cashflow + '/wk</span>' : cashflow < 0 ? '<span style="color:#ef4444">-$' + Math.abs(cashflow) + '/wk</span>' : '—';
    var suburb = ''; var parts = (d.address||'').split(',');
    if (parts.length > 1) suburb = parts[parts.length-2].trim();
    var days = d.days || 0;
    var daysEl = days >= 60 ? '<span style="color:#ef4444;font-weight:700">' + days + 'd 🔥</span>' : days > 0 ? days + 'd' : '—';
    var stamp = priceNum > 0 ? '$' + Math.round(priceNum * 0.035 / 1000) + 'K' : '—';
    var repay = priceNum > 0 ? '$' + Math.round(priceNum * 0.8 * 0.065 / 52) + '/wk' : '—';
    var offerNum = priceNum > 0 ? Math.round(priceNum * 0.88) : 0;
    var offerStr = offerNum > 0 ? '$' + offerNum.toLocaleString() : '—';
    return '<tr onclick="window.open(\'' + d.url + '\',\'_blank\')" style="cursor:pointer">' +
      '<td style="max-width:200px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis">' + (d.address||'—') + '</td>' +
      '<td>' + suburb + '</td>' +
      '<td>' + (d.beds||'?') + 'b ' + (d.baths||'?') + 'ba</td>' +
      '<td style="color:#22c55e;font-weight:600;white-space:nowrap">' + (d.price||'—') + '</td>' +
      '<td>' + daysEl + '</td>' +
      '<td>' + yld + '</td>' +
      '<td>' + (rent ? '$' + rent : '—') + '</td>' +
      '<td>' + cfStr + '</td>' +
      '<td>—</td><td>—</td>' +
      '<td>' + stamp + '</td>' +
      '<td>' + repay + '</td>' +
      '<td>—</td>' +
      '<td onclick="event.stopPropagation();propOpenModal(' + i + ')" style="color:#f59e0b;font-weight:600;cursor:pointer;white-space:nowrap">' + offerStr + '</td>' +
      '<td onclick="event.stopPropagation();propOpenModal(' + i + ')" style="cursor:pointer"><button style="background:#3b82f620;color:#3b82f6;border:1px solid #3b82f640;border-radius:4px;padding:2px 8px;font-size:10px;cursor:pointer">Draft</button></td>' +
    '</tr>';
  }).join('');
}

function propOpenModal(idx) {
  var d = (_propFiltered && _propFiltered.length > idx) ? _propFiltered[idx] : PROP_DEALS[idx];
  if (!d) return;
  document.getElementById('prop-modal-title').textContent = d.address || 'Offer Draft';
  document.getElementById('prop-modal-sub').textContent = (d.price||'') + ' · ' + (d.beds||0) + 'b ' + (d.baths||0) + 'ba · ' + (d.type||'');
  var briefContent = document.getElementById('prop-brief-content');
  if (briefContent) briefContent.textContent = d.brief || '';
  var emailEl = document.getElementById('prop-modal-email');
  if (emailEl) emailEl.textContent = d.email || '';
  document.getElementById('prop-modal-overlay').classList.add('active');
}

function propCloseModal(e) {
  if (e && e.target !== document.getElementById('prop-modal-overlay')) return;
  propCloseModalDirect();
}

function propCloseModalDirect() {
  document.getElementById('prop-modal-overlay').classList.remove('active');
}

function propCopyEmail() {
  var txt = document.getElementById('prop-modal-email').textContent;
  navigator.clipboard.writeText(txt).then(function() {
    var btn = document.querySelector('.prop-btn-copy');
    if (btn) { btn.textContent = 'Copied!'; setTimeout(function() { btn.textContent = 'Copy Email'; }, 2000); }
  });
}

function propToggleColMenu() {
  var m = document.getElementById('prop-col-menu');
  if (m) m.style.display = m.style.display === 'none' ? 'block' : 'none';
}

function propToggleCol(colId, show) {
  var colMap = {
    'col-suburb': 1, 'col-rent': 6, 'col-cashflow': 7,
    'col-growth': 8, 'col-median': 9, 'col-stamp': 10,
    'col-repay': 11, 'col-rating': 12, 'col-offer': 13
  };
  var colIdx = colMap[colId];
  if (!colIdx) return;
  var table = document.querySelector('.prop-table');
  if (!table) return;
  var rows = table.querySelectorAll('tr');
  rows.forEach(function(row) {
    var cells = row.querySelectorAll('th, td');
    if (cells[colIdx]) cells[colIdx].style.display = show ? '' : 'none';
  });
}
